&lt;p&gt;&lt;img src=&#34;https://res.cloudinary.com/dwwbmrctk/image/upload/q_auto/f_auto/v1782072110/74CA82B2-A7A4-4159-9AAD-1E394DCDD65B_e39nad.jpg&#34; width=&#34;471&#34; height=&#34;600&#34; alt=&#34;Fine realities, Rene Magritte, 1964&#34;&gt;&lt;a href=&#34;https://www.wikiart.org/en/rene-magritte/fine-realities-1964&#34;&gt;Fine realities&lt;/a&gt; / Rene Magritte / 1964&lt;/p&gt;
&lt;!-- end-chunk --&gt;
&lt;!-- begin-chunk data-anchor=&#34;heading-7&#34; --&gt;

&lt;h3 class=&#34;header-anchor-wrapper&#34;&gt;&lt;i class=&#34;fa-solid fa-skull-crossbones&#34;&gt;&lt;/i&gt; &lt;i class=&#34;fa-solid fa-skull-crossbones&#34;&gt;&lt;/i&gt; &lt;i class=&#34;fa-solid fa-skull-crossbones&#34;&gt;&lt;/i&gt;
  &lt;a href=&#34;#heading-7&#34; class=&#34;header-anchor-link&#34;&gt;
&lt;svg
    xmlns=&#34;http://www.w3.org/2000/svg&#34;
    width=&#34;1rem&#34; height=&#34;1rem&#34; viewBox=&#34;0 0 24 24&#34; fill=&#34;none&#34;
