&lt;!-- begin-chunk data-anchor=&#34;confusions-6&#34; --&gt;

&lt;h4 class=&#34;header-anchor-wrapper&#34;&gt;Confusions.
  &lt;a href=&#34;#confusions-6&#34; class=&#34;header-anchor-link&#34;&gt;
&lt;svg
    xmlns=&#34;http://www.w3.org/2000/svg&#34;
    width=&#34;1rem&#34; height=&#34;1rem&#34; viewBox=&#34;0 0 24 24&#34; fill=&#34;none&#34;
